# ================== IMPORTS ==================import sysimport mathfrom collections import defaultdict, deque, Counterfrom heapq import heappush, heappopfrom bisect import bisect_left, bisect_right input = sys.stdin.readline # ================== CONSTANTS ==================INF = float('inf')MOD = 10**9 + 7 # ================== TYPE SHORTCUTS ==================ll = int # ================== DEBUG ==================def bug(**kwargs):    print(" | ".join(f"{k} : {v}" for k, v in kwargs.items()), file=sys.stderr) # ================== INPUT ==================def inp(): return int(input())def inlt(): return list(map(int, input().split()))def ins(): return input().strip() # ================== PRINT ==================def print_arr(a): print(*a)def print_yes(): print("YES")def print_no(): print("NO") # ================== MATH ==================def gcd(a, b): return math.gcd(a, b)def lcm(a, b): return a * b // gcd(a, b) def mod_add(a, b, mod=MOD): return (a + b) % moddef mod_sub(a, b, mod=MOD): return (a - b) % moddef mod_mul(a, b, mod=MOD): return (a * b) % mod def mod_exp(a, b, mod=MOD):    res = 1    while b:        if b & 1:            res = res * a % mod        a = a * a % mod        b >>= 1    return res def mod_inv(a, mod=MOD):    return mod_exp(a, mod - 2, mod)  # Fermat (mod must be prime) # ================== ARRAYS ==================def prefix_sum(arr):    ps = [0] * (len(arr) + 1)    for i in range(len(arr)):        ps[i+1] = ps[i] + arr[i]    return ps def suffix_sum(arr):    n = len(arr)    ss = [0] * (n + 1)    for i in range(n-1, -1, -1):        ss[i] = ss[i+1] + arr[i]    return ss # ================== BINARY SEARCH ==================def lower_bound(arr, x):    return bisect_left(arr, x) def upper_bound(arr, x):    return bisect_right(arr, x) # ================== GRAPH ==================def bfs(start, graph, n):    vis = [False] * n    q = deque([start])    vis[start] = True        while q:        node = q.popleft()        for nei in graph[node]:            if not vis[nei]:                vis[nei] = True                q.append(nei) def dfs(node, graph, vis):    vis[node] = True    for nei in graph[node]:        if not vis[nei]:            dfs(nei, graph, vis) # ================== DSU ==================class DSU:    def __init__(self, n):        self.parent = list(range(n))        self.size = [1] * n     def find(self, x):        if self.parent[x] != x:            self.parent[x] = self.find(self.parent[x])        return self.parent[x]     def union(self, a, b):        a = self.find(a)        b = self.find(b)        if a != b:            if self.size[a] < self.size[b]:                a, b = b, a            self.parent[b] = a            self.size[a] += self.size[b] # ================== SOLVE ==================def solve():    n, x = map(int, input().split())    a = list(map(int, input().split()))     max_diff = a[0]    for i in range(1, n):        max_diff = max(max_diff, a[i] - a[i-1])     ans = max(max_diff, (x-a[n-1])*2)     print(ans)  # ================== MAIN ==================def main():    t = 1    try:        t = int(input())    except:        pass        for _ in range(t):        solve()  if __name__ == "__main__":    main()